SELECT ml_model_name
FROM ml_models
WHERE ml_model_id = 0;

SELECT res_allocation.allocation_status
FROM resource_allocation AS res_allocation
WHERE res_allocation.time_step_id = 1;

SELECT qos_throughput, aver_delay
FROM qos_metrics
WHERE qos_metric_type = 'delay';

SELECT qos_id, time_step_id, total_reqs, n_succ, aver_delay
FROM qos_metrics
ORDER BY time_step_id;
